import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

/**
 * 创建一个 9x9 的空棋盘，作为游戏初始化占位状态。
 *
 * @returns {number[][]}
 */
function createEmptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0));
}

/**
 * 创建初始 `Game` 对象。
 *
 * 这里使用全 0 棋盘只是为了让 store 在应用挂载前就具备完整接口，
 * 真正开局会在 `generate` 或 `decodeSencode` 时替换整局会话。
 *
 * @returns {ReturnType<typeof createGame>}
 */
function createInitialGame() {
	return createGame({ sudoku: createSudoku(createEmptyGrid()) });
}

/**
 * 创建连接 Svelte 与领域对象的适配层。
 *
 * 内部持有真正的 `Game`，对外暴露的是可订阅的纯数据状态和命令式接口。
 * 这样组件无需理解领域对象内部细节，只需要消费 store。
 *
 * @returns {{
 *   subscribe: import('svelte/store').Readable<number[][]>['subscribe'],
 *   userGridSubscribe: import('svelte/store').Readable<number[][]>['subscribe'],
 *   invalidCellsSubscribe: import('svelte/store').Readable<string[]>['subscribe'],
 *   canUndoSubscribe: import('svelte/store').Readable<boolean>['subscribe'],
 *   canRedoSubscribe: import('svelte/store').Readable<boolean>['subscribe'],
 *   wonSubscribe: import('svelte/store').Readable<boolean>['subscribe'],
 *   generate: (difficulty: string) => void,
 *   decodeSencode: (sencode: string) => void,
 *   get: (gridStore: number[][], x: number, y: number) => number,
 *   getSencode: (gridStore: number[][]) => string,
 *   set: (pos: { x: number | null, y: number | null }, value: number) => boolean,
 *   applyHint: (pos: { x: number | null, y: number | null }) => boolean,
 *   undo: () => boolean,
 *   redo: () => boolean
 * }}
 */
function createGrid() {
	let currentGame = createInitialGame();
	const state = writable(currentGame.getState());

	const puzzleGrid = derived(state, $state => $state.puzzleGrid);
	const currentGrid = derived(state, $state => $state.grid);
	const invalidCells = derived(state, $state => $state.invalidCells);
	const canUndo = derived(state, $state => $state.canUndo);
	const canRedo = derived(state, $state => $state.canRedo);
	const won = derived(state, $state => $state.won);

	/**
	 * 将领域对象的最新状态重新投影到 Svelte store。
	 *
	 * 注意这里必须调用 `set`，因为 Svelte 不会自动追踪普通对象内部字段变化。
	 */
	function syncFromGame() {
		// Svelte 只会对 store 的 set/update 做出反应，所以领域对象变更后要重新外表化成新状态。
		state.set(currentGame.getState());
	}

	/**
	 * 用新的题面创建整局游戏，并重置 undo/redo 历史。
	 *
	 * @param {number[][]} nextGrid
	 */
	function resetGame(nextGrid) {
		currentGame = createGame({ sudoku: createSudoku(nextGrid) });
		syncFromGame();
	}

	/**
	 * 判断当前光标是否已经落在一个实际格子上。
	 *
	 * @param {{ x: number | null, y: number | null }} pos
	 * @returns {boolean}
	 */
	function hasCursor(pos) {
		return pos && pos.x !== null && pos.y !== null;
	}

	return {
		subscribe: puzzleGrid.subscribe,
		userGridSubscribe: currentGrid.subscribe,
		invalidCellsSubscribe: invalidCells.subscribe,
		canUndoSubscribe: canUndo.subscribe,
		canRedoSubscribe: canRedo.subscribe,
		wonSubscribe: won.subscribe,

		/**
		 * 按难度生成新题并开始新游戏。
		 *
		 * @param {string} difficulty
		 */
		generate(difficulty) {
			resetGame(generateSudoku(difficulty));
		},

		/**
		 * 从分享编码恢复题面并开始新游戏。
		 *
		 * @param {string} sencode
		 */
		decodeSencode(sencode) {
			resetGame(decodeSencode(sencode));
		},

		/**
		 * 读取二维棋盘中某个位置的值。
		 *
		 * @param {number[][]} gridStore
		 * @param {number} x
		 * @param {number} y
		 * @returns {number}
		 */
		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		/**
		 * 将棋盘编码为可分享的 sencode 字符串。
		 *
		 * 这里传入的通常是题面固定格，而不是玩家当前进度，
		 * 这样分享出去的是“题目”而不是“存档”。
		 *
		 * @param {number[][]} gridStore
		 * @returns {string}
		 */
		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},

		/**
		 * 向当前选中格写入一个值。
		 *
		 * @param {{ x: number | null, y: number | null }} pos
		 * @param {number} value
		 * @returns {boolean}
		 */
		set(pos, value) {
			if (!hasCursor(pos)) {
				return false;
			}

			const changed = currentGame.guess({ row: pos.y, col: pos.x, value });
			if (changed) {
				syncFromGame();
			}

			return changed;
		},

		/**
		 * 根据求解结果向当前格填入提示值。
		 *
		 * 仍然走 `Game.guess(...)`，这样提示和普通输入共用同一套
		 * 领域规则与 undo/redo 机制。
		 *
		 * @param {{ x: number | null, y: number | null }} pos
		 * @returns {boolean}
		 */
		applyHint(pos) {
			if (!hasCursor(pos)) {
				return false;
			}

			if (currentGame.getState().invalidCells.length > 0) {
				return false;
			}

			// 提示值基于当前盘面求解，而不是基于原始题面，
			// 这样玩家已有输入会参与求解过程。
			let solvedSudoku;
			try {
				solvedSudoku = solveSudoku(get(currentGrid));
			} catch {
				return false;
			}

			const changed = currentGame.guess({
				row: pos.y,
				col: pos.x,
				value: solvedSudoku[pos.y][pos.x],
			});

			if (changed) {
				hints.useHint();
				syncFromGame();
			}

			return changed;
		},

		/**
		 * 撤销最近一次输入。
		 *
		 * @returns {boolean}
		 */
		undo() {
			const changed = currentGame.undo();
			if (changed) {
				syncFromGame();
			}

			return changed;
		},

		/**
		 * 重做最近一次被撤销的输入。
		 *
		 * @returns {boolean}
		 */
		redo() {
			const changed = currentGame.redo();
			if (changed) {
				syncFromGame();
			}

			return changed;
		},
	};
}

/**
 * 固定格题面 store。
 *
 * 组件通过 `$grid` 渲染哪些格子是题目原始 givens。
 */
export const grid = createGrid();

/**
 * 当前盘面 store 以及与玩家输入相关的命令。
 */
export const userGrid = {
	subscribe: grid.userGridSubscribe,
	set: (pos, value) => grid.set(pos, value),
	applyHint: pos => grid.applyHint(pos),
};

/**
 * 当前所有冲突格的坐标列表。
 */
export const invalidCells = {
	subscribe: grid.invalidCellsSubscribe,
};

/**
 * 是否仍可撤销。
 */
export const canUndo = {
	subscribe: grid.canUndoSubscribe,
};

/**
 * 是否仍可重做。
 */
export const canRedo = {
	subscribe: grid.canRedoSubscribe,
};

/**
 * 当前局面是否已经完成并获胜。
 */
export const won = {
	subscribe: grid.wonSubscribe,
};
